param([Parameter(Mandatory=$true)][string]$IncomingRoot,[Parameter(Mandatory=$true)][string]$RunId,[ValidateSet('GDAXI','AUDCAD')][string]$Symbol='GDAXI')
$ErrorActionPreference='Stop';$target='execution';$csvName='nora_phase2_execution_tester_v1.csv';$terminal='C:\Program Files\Darwinex MetaTrader 5\terminal64.exe';$root=Join-Path $env:USERPROFILE 'NoraPhase2ExecutionValidation\evidence-v2';$run=Join-Path $root $RunId
function FileHash($p){(Get-FileHash -LiteralPath $p -Algorithm SHA256).Hash.ToLowerInvariant()}
if(Test-Path $run){throw 'occupied run destination'};New-Item -ItemType Directory $run|Out-Null
try{$packetPath=Join-Path $IncomingRoot 'execution_packet.json';$batchPath=Join-Path $IncomingRoot 'final_batch.json';if(!(Test-Path $packetPath) -or !(Test-Path $batchPath)){throw 'missing final packet'};$packet=Get-Content $packetPath -Raw|ConvertFrom-Json;$batch=Get-Content $batchPath -Raw|ConvertFrom-Json;if($packet.schema_version -ne 'nora.execution_native_packet_v1' -or $batch.schema_version -ne 'nora.execution_final_native_batch_v1'){throw 'wrong final packet schema'};$complete=$packet.completion_marker;$fail=$packet.failure_marker;$ex5=Join-Path $IncomingRoot ('compile\'+$packet.ex5_path);if(!(Test-Path $ex5) -or (FileHash $ex5) -ne $packet.ex5_sha256 -or (Get-Item $ex5).Length -ne $packet.ex5_size){throw 'bound EX5 mismatch'};$data=Get-ChildItem "$env:APPDATA\MetaQuotes\Terminal" -Directory|?{(Test-Path (Join-Path $_.FullName 'origin.txt')) -and ((Get-Content (Join-Path $_.FullName 'origin.txt') -Raw).Trim() -eq 'C:\Program Files\Darwinex MetaTrader 5')}|select -First 1 -Expand FullName;if(!$data){throw 'Darwinex data root absent'};if(Get-Process terminal64 -ErrorAction SilentlyContinue){throw 'conflicting terminal'};$expertDir=Join-Path $data 'MQL5\Experts\NoraPhase2Execution';New-Item -ItemType Directory -Force $expertDir|Out-Null;$installed=Join-Path $expertDir 'NoraPhase2ExecutionTesterCanaryV1.ex5';Copy-Item $ex5 $installed -Force;if((FileHash $installed) -ne $packet.ex5_sha256){throw 'installed EX5 mismatch'};$common=Join-Path (Split-Path $data -Parent) 'Common\Files';$commonCsv=Join-Path $common $csvName;if(Test-Path $commonCsv){Remove-Item $commonCsv -Force};$journal=Join-Path $data ('Tester\logs\'+(Get-Date -Format yyyyMMdd)+'.log');$before=if(Test-Path $journal){(Get-Item $journal).Length}else{0};$ini=Get-Content 'C:\Program Files\Darwinex MetaTrader 5\backtest_run.ini' -Raw;$ini=[regex]::Replace($ini,'(?m)^Expert=.*$','Expert=NoraPhase2Execution\NoraPhase2ExecutionTesterCanaryV1');$ini=[regex]::Replace($ini,'(?m)^Symbol=.*$',('Symbol='+$Symbol));$ini=[regex]::Replace($ini,'(?m)^Period=.*$','Period=M1');$ini=[regex]::Replace($ini,'(?m)^Report=.*$',('Report='+(Join-Path $run 'tester.htm')));$ini=[regex]::Replace($ini,'(?m)^ReplaceReport=.*$','ReplaceReport=1');Set-Content (Join-Path $run 'tester.ini') $ini -Encoding ascii;$start=(Get-Date).ToUniversalTime();$p=Start-Process $terminal -ArgumentList ('/config:"'+(Join-Path $run 'tester.ini')+'"') -PassThru;if(!$p.WaitForExit(120000)){$p.Kill();throw 'tester timeout'};$end=(Get-Date).ToUniversalTime();if(!(Test-Path $commonCsv)){throw 'missing fresh csv'};Copy-Item $commonCsv (Join-Path $run $csvName);$segment=if(Test-Path $journal){$fs=[IO.File]::OpenRead($journal);$fs.Seek($before,[IO.SeekOrigin]::Begin)|Out-Null;$count=$fs.Length-$before;$bytes=New-Object byte[] $count;$null=$fs.Read($bytes,0,$count);$fs.Close();[Text.Encoding]::Unicode.GetString($bytes)}else{''};$segment|Set-Content (Join-Path $run 'tester-journal.log') -Encoding utf8;$completion=$segment -match [regex]::Escape($complete);$failure=$segment -match [regex]::Escape($fail);@{marker=$complete;present=$completion}|ConvertTo-Json|Set-Content (Join-Path $run 'completion-marker.json') -Encoding utf8;@{marker=$fail;present=$failure}|ConvertTo-Json|Set-Content (Join-Path $run 'failure-marker.json') -Encoding utf8;if(!$completion -or $failure){throw 'marker state failed'};$report=Join-Path $run 'tester.htm';if(!(Test-Path $report)){@{schema_version='nora.phase2.execution_tester_evidence_v1';run_identifier=$RunId;symbol=$Symbol;timeframe='M1';start_utc=$start.ToString('o');completion_utc=$end.ToString('o');ex5_sha256=$packet.ex5_sha256;csv_sha256=FileHash (Join-Path $run $csvName);journal_sha256=FileHash (Join-Path $run 'tester-journal.log');completion_marker_present=$completion;failure_marker_present=$failure;no_trading_operations=$true;substitute='native journal-bounded tester evidence'}|ConvertTo-Json -Depth 5|Set-Content $report -Encoding utf8};Copy-Item (Join-Path $IncomingRoot 'compile\compiler_record.json') (Join-Path $run 'compile.json');Copy-Item (Join-Path $IncomingRoot 'compile\compile.log') (Join-Path $run 'compile.log');$record=[ordered]@{schema_version='nora.execution_run_record_v2';run_identifier=$RunId;target_identifier=$target;host_symbol=$Symbol;timeframe='M1';requested_start_utc=$start.ToString('o');observed_completion_utc=$end.ToString('o');final_batch_identity=$batch.final_batch_identity;compile_input_identity=$packet.compile_input_identity;compiler_output_identity=$packet.compiler_output_identity;execution_packet_identity=$packet.execution_packet_identity;ex5_sha256=$packet.ex5_sha256;runtime_identity=$packet.runtime_identity;tester_identity=$packet.tester_identity;package_identity=$packet.package_identity;execution_plan_identity=$packet.execution_plan_identity;expected_vector_identity=$packet.expected_vector_identity;csv_schema_identity=$packet.csv_schema_identity;tester_configuration_sha256=FileHash (Join-Path $run 'tester.ini');result_csv_sha256=FileHash (Join-Path $run $csvName);journal_source=$journal;journal_baseline_bytes=$before;journal_segment_sha256=FileHash (Join-Path $run 'tester-journal.log');completion_marker_present=$completion;failure_marker_present=$failure;process_exit=$p.ExitCode;no_trading_operations=$true;collection_state='complete'};$record|ConvertTo-Json -Depth 8|Set-Content (Join-Path $run 'execution.json') -Encoding utf8;Write-Output $run}catch{@{run_identifier=$RunId;collection_state='failed';failure=$_.Exception.Message}|ConvertTo-Json|Set-Content (Join-Path $run 'execution.json') -Encoding utf8;throw}
